// Parse KML and extract geocercas data
const kmlContent = $input.first().json.data;

// Function to parse XML
function parseXML(xmlString) {
  const parser = new DOMParser();
  return parser.parseFromString(xmlString, 'text/xml');
}

// Function to detect type based on name
function detectType(name) {
  const nameUpper = name.toUpperCase();

  if (nameUpper.includes('TALLER')) return 'taller';
  if (nameUpper.includes('CASETA') || nameUpper.includes('PEAJE')) return 'caseta';
  if (nameUpper.includes('PUERTO') || nameUpper.includes('ADUANA')) return 'puerto';
  if (nameUpper.includes('CLIENTE') || nameUpper.includes('ALMACEN') || nameUpper.includes('BODEGA')) return 'cliente';

  return 'otro';
}

// Parse KML
const xmlDoc = parseXML(kmlContent);
const placemarks = xmlDoc.getElementsByTagName('Placemark');

const geocercas = [];
const now = new Date().toISOString().slice(0, 19).replace('T', ' ');

for (let i = 0; i < placemarks.length; i++) {
  const placemark = placemarks[i];

  try {
    // Extract name
    const nameElem = placemark.getElementsByTagName('name')[0];
    const name = nameElem ? nameElem.textContent.trim() : 'Sin nombre';

    // Extract description (address)
    const descElem = placemark.getElementsByTagName('description')[0];
    let description = '';
    if (descElem && descElem.textContent) {
      const descText = descElem.textContent.trim();
      // Remove image data if present
      if (descText.includes('img_data=')) {
        const parts = descText.split('>');
        description = parts.length > 1 ? parts[parts.length - 1].trim() : descText;
      } else {
        description = descText;
      }
    }

    // Extract polygon coordinates
    const coordsElem = placemark.getElementsByTagName('coordinates')[0];
    if (!coordsElem || !coordsElem.textContent) {
      console.log(`Warning: No coordinates for ${name}`);
      continue;
    }

    // Parse coordinates (format: lng,lat,alt lng,lat,alt ...)
    const coordsText = coordsElem.textContent.trim();
    const coordPairs = [];

    for (const coord of coordsText.split(/\s+/)) {
      const parts = coord.split(',');
      if (parts.length >= 2) {
        const lng = parseFloat(parts[0]);
        const lat = parseFloat(parts[1]);
        if (!isNaN(lat) && !isNaN(lng)) {
          coordPairs.push([lat, lng]);
        }
      }
    }

    if (coordPairs.length === 0) {
      console.log(`Warning: No valid coordinates for ${name}`);
      continue;
    }

    // Calculate center point (average of all coordinates)
    const avgLat = coordPairs.reduce((sum, pair) => sum + pair[0], 0) / coordPairs.length;
    const avgLng = coordPairs.reduce((sum, pair) => sum + pair[1], 0) / coordPairs.length;

    // Auto-detect type
    const tipo = detectType(name);

    // Create geocerca entry
    geocercas.push({
      nombre: name,
      descripcion: description,
      lat: Math.round(avgLat * 1000000) / 1000000,
      lng: Math.round(avgLng * 1000000) / 1000000,
      tipo: tipo,
      poligono_coords: JSON.stringify(coordPairs),
      fecha_creacion: now
    });

  } catch (error) {
    console.error(`Error parsing placemark: ${error.message}`);
    continue;
  }
}

console.log(`Parsed ${geocercas.length} geocercas from KML`);

// Return as array for n8n
return geocercas.map(g => ({ json: g }));
